import { Avatar, Badge, Card, Col, QRCode, Row, Space, Typography } from "antd"
import {
  Award,
  Briefcase,
  CalendarCheck,
  CheckCircle,
  CreditCard,
  Mail,
  MapPin,
  Phone,
  User,
} from "lucide-react"
import PropTypes from "prop-types"
import bgDrum from "../../../../assets/images/logo/AX51-vector-corel-trong-dong.jpg"
import logo from "../../../../assets/images/logo/logo3.png"
import "../styles/CustomMemberCard.scss"
import "./MemberCard.scss"

const { Title, Text, Paragraph } = Typography

export default function CustomMemberCard({ memberData }) {
  const currentDate = new Date()
  const expiryDate = new Date(currentDate.getFullYear() + 5, 11, 31)
  const memberID = `HV${String(Math.floor(Math.random() * 1000000)).padStart(
    6,
    "0",
  )}`

  return (
    <div className="member-card">
      <div
        style={{
          backgroundSize: "cover",
          backgroundRepeat: "no-repeat",
          backgroundPosition: "center center",
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
        }}
      >
        <div>
          <div
            style={{
              borderRadius: 20,
              overflow: "hidden",
              backgroundColor: "rgba(255, 255, 255, 0.85)",
              border: "none",
              position: "relative",
            }}
          >
            <div
              style={{
                position: "absolute",
                borderRadius: 20,
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                backgroundImage: `url(${bgDrum})`,
                backgroundRepeat: "no-repeat",
                backgroundPosition: "center",
                backgroundSize: "cover",
                opacity: 0.4,
                pointerEvents: "none",
                zIndex: 0,
              }}
            />
            {/* Enhanced Header */}
            <div
              className="enhanced-header"
              style={{
                borderRadius: 20,
                padding: "32px 32px 24px",
                color: "white",
                position: "relative",
                overflow: "hidden",
              }}
            >
              {/* Background decorative elements */}
              <div
                style={{
                  position: "absolute",
                  width: 200,
                  height: 200,
                  background: "rgba(255,255,255,0.05)",
                  borderRadius: "50%",
                }}
              />
              <div
                style={{
                  position: "absolute",
                  bottom: -30,
                  left: -30,
                  width: 150,
                  height: 150,
                  background: "rgba(255,255,255,0.03)",
                  borderRadius: "50%",
                }}
              />

              <Row justify="space-between" align="top" className="header-row">
                <Col>
                  <Space size="middle" align="center">
                    <div
                      style={{
                        borderRadius: 16,
                        backdropFilter: "blur(10px)",
                      }}
                      className="logo-card"
                    >
                      <img
                        src={logo}
                        alt="logoHHTVNCSK"
                        style={{ width: 55, height: 55 }}
                        className="logo"
                      />
                    </div>
                    <div className="card-info">
                      <Title
                        level={4}
                        style={{ margin: 0, color: "#1e3a8a", fontWeight: 700 }}
                        className="card-title"
                      >
                        Hiệp Hội Tư Vấn Nâng Cao Sức Khỏe
                      </Title>
                      <Text
                        style={{ color: "#475569", fontSize: 14 }}
                        className="card-name"
                      >
                        Thẻ Hội Viên Cá Nhân
                      </Text>
                    </div>
                  </Space>
                </Col>
                <Col
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    justifyContent: "center",
                    alignItems: "flex-end",
                    textAlign: "right",
                    marginRight: "10px",
                  }}
                >
                  <div
                    style={{
                      borderRadius: 8,
                      border: "1px solid #e2e8f0",
                    }}
                  >
                    <QRCode
                      value={`${window.location.origin}/memberinfo?userId=${memberData.UserID}&memberType=${memberData?.MemberType}`}
                      size={50}
                      bordered={false}
                    />
                  </div>
                </Col>
              </Row>
            </div>

            {/* Enhanced Body */}
            <Row gutter={0} className="custom-member-card__body">
              {/* Left Panel - Member Profile */}
              <Col
                className="custom-member-card__left"
                style={{
                  background:
                    "linear-gradient(180deg,rgba(213, 220, 228, 0) 0%,rgba(255, 255, 255, 0) 100%)",
                  padding: 20,
                  paddingTop: 40,
                  borderRight: "1px solid #e2e8f0",
                  alignItems: "center",
                  gap: 20,
                }}
              >
                {/* Enhanced Avatar */}
                <div style={{ position: "relative" }}>
                  <Avatar
                    className="avatar-member"
                    size={150}
                    style={{
                      background:
                        "linear-gradient(135deg, #e2e8f0 0%, #f1f5f9 100%)",
                      border: "6px solid white",
                      boxShadow: "0 12px 24px rgba(0,0,0,0.15)",
                    }}
                    src={memberData.Avatar}
                    icon={<User size={60} color="#94a3b8" />}
                  />
                  <div
                    className="avatar-badge"
                    style={{
                      position: "absolute",
                      bottom: 8,
                      right: 8,
                      backgroundColor: "#22c55e",
                      width: 32,
                      height: 32,
                      borderRadius: "50%",
                      border: "4px solid white",
                      display: "flex",
                      justifyContent: "center",
                      alignItems: "center",
                      boxShadow: "0 4px 8px rgba(0,0,0,0.2)",
                    }}
                  >
                    <CheckCircle size={16} color="white" />
                  </div>
                </div>

                {/* Member Info */}
                <div className="member-info">
                  <div
                    className="member-name"
                    style={{
                      textAlign: "center",
                      width: "100%",
                      fontSize: 26,
                      fontWeight: "bold",
                    }}
                  >
                    {memberData.FullName || "N/A"}
                  </div>

                  <div className="member-id">
                    {/* Member ID with copy function */}
                    <div
                      className="member-id-card"
                      style={{
                        borderRadius: 16,
                        width: "100%",
                        textAlign: "center",
                        border: "2px solid #e0f2fe",
                      }}
                    >
                      <Text
                        style={{
                          color: "#0369a1",
                          fontWeight: 600,
                          fontSize: 11,
                          letterSpacing: 1.5,
                          textTransform: "uppercase",
                        }}
                        className="member-id-code"
                      >
                        Mã số hội viên
                      </Text>
                      <div
                        style={{
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          marginTop: 8,
                        }}
                      >
                        <Text
                          style={{
                            fontFamily: "'JetBrains Mono', monospace",
                            fontWeight: "bold",
                            fontSize: 18,
                            color: "#0c4a6e",
                            marginRight: 8,
                          }}
                          className="member-code-value"
                        >
                          {memberID}
                        </Text>
                      </div>
                    </div>

                    <Space size={8} style={{ marginTop: 8 }}>
                      <Text style={{ color: "#64748b", fontSize: 12 }}>
                        Hiệu lực đến:
                      </Text>
                      <Text
                        style={{
                          color: "#1e3a8a",
                          fontWeight: 700,
                          fontSize: 16,
                        }}
                        className="member-code-value"
                      >
                        {expiryDate.toLocaleDateString("vi-VN")}
                      </Text>
                    </Space>
                  </div>
                </div>
              </Col>

              {/* Right Panel - Contact & Actions */}
              <Col
                style={{ padding: 20, paddingTop: 0 }}
                className="custom-member-card__right"
              >
                <Space
                  direction="vertical"
                  size="large"
                  style={{ width: "100%" }}
                >
                  {/* Section Header */}
                  <div className="section-header">
                    <Space size={12} align="center" style={{ marginBottom: 8 }}>
                      <CreditCard size={24} color="#2563eb" />
                      <Title level={3} style={{ margin: 0, color: "#1e293b" }}>
                        Thông Tin Cá Nhân
                      </Title>
                    </Space>
                  </div>

                  <Row gutter={[16, 16]} className="section-content">
                    {/* Phone */}
                    <Col sm={24} lg={12}>
                      <Card
                        bordered={false}
                        style={{ padding: 0, backgroundColor: "transparent" }}
                        bodyStyle={{
                          padding: 16,
                          backgroundColor: "transparent",
                        }}
                      >
                        <Space size="middle" align="start" className="contact">
                          <Phone size={18} color="#475569" />
                          <div className="contact-info">
                            <Text
                              style={{
                                fontSize: 12,
                                color: "#64748b",
                                textTransform: "uppercase",
                              }}
                              className="contact-label"
                            >
                              Số điện thoại
                            </Text>
                            <div
                              style={{ marginTop: 4 }}
                              className="contact-value"
                            >
                              <Text
                                style={{
                                  fontSize: 15,
                                  fontWeight: 600,
                                  color: "#0f172a",
                                }}
                              >
                                {memberData.PhoneNumber || "N/A"}
                              </Text>
                            </div>
                          </div>
                        </Space>
                      </Card>
                    </Col>

                    {/* Email */}
                    <Col sm={24} lg={12}>
                      <Card
                        bordered={false}
                        style={{ padding: 0, backgroundColor: "transparent" }}
                        bodyStyle={{
                          padding: 16,
                          backgroundColor: "transparent",
                        }}
                      >
                        <Space size="middle" align="start">
                          <Mail size={18} color="#475569" />
                          <div className="contact-info">
                            <Text
                              style={{
                                fontSize: 12,
                                color: "#64748b",
                                textTransform: "uppercase",
                              }}
                              className="contact-label"
                            >
                              Email
                            </Text>
                            <Paragraph
                              style={{
                                margin: 0,
                                fontSize: 15,
                                fontWeight: 600,
                                color: "#0f172a",
                                marginTop: 4,
                              }}
                              className="contact-value"
                            >
                              {memberData.Email || "N/A"}
                            </Paragraph>
                          </div>
                        </Space>
                      </Card>
                    </Col>

                    {/* Address */}
                    <Col>
                      <Card
                        bordered={false}
                        style={{ padding: 0, backgroundColor: "transparent" }}
                        bodyStyle={{
                          padding: 16,
                          backgroundColor: "transparent",
                        }}
                      >
                        <Space size="middle" align="start">
                          <MapPin
                            size={18}
                            color="#475569"
                          />
                          <div className="contact-info">
                            <Text
                              style={{
                                fontSize: 12,
                                color: "#64748b",
                                textTransform: "uppercase",
                              }}
                              className="contact-label"
                            >
                              Địa chỉ liên hệ
                            </Text>
                            <div
                              style={{ marginTop: 4 }}
                              className="contact-value"
                            >
                              <Text
                                style={{
                                  fontSize: 15,
                                  fontWeight: 600,
                                  color: "#0f172a",
                                  lineHeight: 1.6,
                                }}
                              >
                                {memberData.ResidenceAddress || "N/A"}
                              </Text>
                            </div>
                          </div>
                        </Space>
                      </Card>
                    </Col>
                  </Row>

                  {/* Enhanced Status Badges */}
                  <Row
                    gutter={[24, 24]}
                    style={{ padding: "10px 32px" }}
                    className="custom-member-card__badges"
                  >
                    <Col
                      xs={24}
                      sm={24}
                      lg={12}
                      className="custom-member-card__badges-col"
                    >
                      {/* Gói hội viên */}
                      <div style={{ marginBottom: 12 }}>
                        <Text
                          style={{
                            fontSize: 12,
                            color: "#64748b",
                            textTransform: "uppercase",
                            display: "block",
                            marginBottom: 4,
                          }}
                          className="contact-label"
                        >
                          <CheckCircle
                            size={14}
                            style={{ marginRight: 6, display: "none" }}
                            className="custom-member-card__badges-icon"
                          />
                          Gói hội viên
                        </Text>
                        <Badge
                          style={{
                            padding: "8px 16px",
                            borderRadius: 20,
                            fontWeight: 600,
                            fontSize: 13,
                            backgroundColor: "#dbeafe",
                            color: "#1d4ed8",
                            border: "2px solid #93c5fd",
                          }}
                          className="valueName"
                        >
                          <CheckCircle size={14} style={{ marginRight: 6 }} />
                          {memberData.PackageName || "N/A"}
                        </Badge>
                      </div>

                      {/* Tên chi hội */}
                      <div>
                        <Text
                          style={{
                            fontSize: 12,
                            color: "#64748b",
                            textTransform: "uppercase",
                            display: "block",
                            marginBottom: 4,
                          }}
                          className="contact-label"
                        >
                          <Award
                            size={14}
                            style={{ marginRight: 6, display: "none" }}
                            className="custom-member-card__badges-icon"
                          />
                          Chi hội
                        </Text>
                        <Badge
                          style={{
                            padding: "8px 16px",
                            borderRadius: 20,
                            fontWeight: 600,
                            fontSize: 13,
                            backgroundColor: "#fef3c7",
                            color: "#d97706",
                            border: "2px solid #fcd34d",
                          }}
                          className="valueName"
                        >
                          <Award size={14} style={{ marginRight: 6 }} />
                          {memberData.AssociationName || "Chưa có chi hội"}
                        </Badge>
                      </div>
                    </Col>
                    <Col
                      xs={24}
                      sm={24}
                      lg={12}
                      className="custom-member-card__badges-col"
                    >
                      {/* Chức vụ */}
                      <div style={{ marginBottom: 12 }}>
                        <Text
                          style={{
                            fontSize: 12,
                            color: "#64748b",
                            textTransform: "uppercase",
                            display: "block",
                            marginBottom: 4,
                          }}
                          className="contact-label"
                        >
                          <Briefcase
                            size={14}
                            style={{ marginRight: 6, display: "none" }}
                            className="custom-member-card__badges-icon"
                          />
                          Chức vụ
                        </Text>
                        <Badge
                          style={{
                            padding: "8px 16px",
                            borderRadius: 20,
                            fontWeight: 600,
                            fontSize: 13,
                            backgroundColor: "#e0f2fe",
                            color: "#0369a1",
                            border: "2px solid #bae6fd",
                          }}
                          className="valueName"
                        >
                          <Briefcase size={14} style={{ marginRight: 6 }} />
                          {memberData.Occupation || "Không rõ"}
                        </Badge>
                      </div>

                      {/* Ngày gia nhập */}
                      <div>
                        <Text
                          style={{
                            fontSize: 12,
                            color: "#64748b",
                            textTransform: "uppercase",
                            display: "block",
                            marginBottom: 4,
                          }}
                          className="contact-label"
                        >
                          <CalendarCheck
                            size={14}
                            style={{ marginRight: 6, display: "none" }}
                            className="custom-member-card__badges-icon"
                          />
                          Ngày gia nhập
                        </Text>
                        <Badge
                          style={{
                            padding: "8px 16px",
                            borderRadius: 20,
                            fontWeight: 600,
                            fontSize: 13,
                            backgroundColor: "#dcfce7",
                            color: "#15803d",
                            border: "2px solid #bbf7d0",
                          }}
                          className="valueName"
                        >
                          <CalendarCheck size={14} style={{ marginRight: 6 }} />
                          {memberData.CreateDate
                            ? new Date(
                                memberData.CreateDate,
                              ).toLocaleDateString("vi-VN")
                            : "Không rõ"}
                        </Badge>
                      </div>
                    </Col>
                  </Row>
                </Space>
              </Col>
            </Row>

            {/* Enhanced Footer */}
            <div
              style={{
                background: "linear-gradient(90deg, #f8fafc 0%, #f1f5f9 100%)",
                padding: "20px 32px",
                borderTop: "1px solid #e2e8f0",
                textAlign: "center",
              }}
              className="custom-member-card__footer"
            >
              <Text style={{ color: "#64748b", fontSize: 13 }}>
                🏛️ Thẻ hội viên này được cấp bởi{" "}
                <strong>Hiệp Hội Tư Vấn Nâng Cao Sức Khỏe</strong> và có giá trị
                pháp lý
              </Text>
            </div>
          </div>
        </div>
      </div>
      <div
        style={{
          height: "100%",
          overflowY: "auto",
        }}
      >
        {/* Nội dung của bạn */}
      </div>
    </div>
  )
}

CustomMemberCard.propTypes = {
  memberData: PropTypes.shape({
    MemberType: PropTypes.string,
    UserID: PropTypes.string,
    FullName: PropTypes.string,
    PhoneNumber: PropTypes.string,
    Email: PropTypes.string,
    Address: PropTypes.string,
    ContactAddress: PropTypes.string,
    ResidenceAddress: PropTypes.string,
    Avatar: PropTypes.string,
    PackageName: PropTypes.string,
    AssociationName: PropTypes.string,
    Identification: PropTypes.string,
    DateOfBirth: PropTypes.string,
    Occupation: PropTypes.string,
    CreateDate: PropTypes.string,
  }).isRequired,
  open: PropTypes.bool.isRequired,
  onCancel: PropTypes.func.isRequired,
}
